content:
{
  "sentences": [
    {
      "text": "那個人長得很高，也很瘦。",
      "pinyin": "Nà ge rén zhǎng de hěn gāo, yě hěn shòu.",
      "pinyin_numeric": "na4 ge4 ren2 zhang3 de5 hen3 gao1, ye3 hen3 shou4",
      "translation_en": "That person is very tall and also very thin.",
      "translation_ko": "그 사람은 키가 매우 크고, 또한 매우 날씬합니다."
    },
    {
      "text": "我妹妹的個性很活潑，她喜歡說話。",
      "pinyin": "Wǒ mèimei de gèxìng hěn huópō, tā xǐhuān shuōhuà.",
      "pinyin_numeric": "wo3 mei4mei5 de5 ge4xing4 hen3 huo2po1, ta1 xi3huan1 shuo1hua4",
      "translation_en": "My younger sister's personality is very lively; she likes to talk.",
      "translation_ko": "제 여동생의 성격은 매우 활발해서 말하기를 좋아합니다."
    },
    {
      "text": "他戴眼鏡，看起來很聰明。",
      "pinyin": "Tā dài yǎnjìng, kàn qǐlái hěn cōngmíng.",
      "pinyin_numeric": "ta1 dai4 yan3jing4, kan4 qi3lai2 hen3 cong1ming2",
      "translation_en": "He wears glasses and looks very smart.",
      "translation_ko": "그는 안경을 쓰고 있어서 매우 똑똑해 보입니다."
    },
    {
      "text": "我認識一個很幽默的朋友，他常常讓我們笑。",
      "pinyin": "Wǒ rènshi yī ge hěn yōumò de péngyou, tā chángcháng ràng wǒmen xiào.",
      "pinyin_numeric": "wo3 ren4shi5 yi1 ge5 hen3 you1mo4 de5 peng2you3, ta1 chang2chang2 rang4 wo3men xiao4",
      "translation_en": "I know a very humorous friend; he often makes us laugh.",
      "translation_ko": "저는 매우 유머러스한 친구를 알고 있는데, 그는 자주 우리를 웃게 합니다."
    },
    {
      "text": "那個女生穿著白色的衣服，長得很漂亮。",
      "pinyin": "Nà ge nǚshēng chuān zhe báisè de yīfu, zhǎng de hěn piàoliang.",
      "pinyin_numeric": "na4 ge5 nü3sheng1 chuan1 zhe5 bai2se4 de5 yi1fu5, zhang3 de5 hen3 piao4liang5",
      "translation_en": "That girl is wearing white clothes and looks very pretty.",
      "translation_ko": "그 여학생은 흰색 옷을 입고 있으며, 매우 예쁘게 생겼습니다."
    },
    {
      "text": "我哥哥的個性很認真，他工作很努力。",
      "pinyin": "Wǒ gēge de gèxìng hěn rènzhēn, tā gōngzuò hěn nǔlì.",
      "pinyin_numeric": "wo3 ge1ge5 de5 ge4xing4 hen3 ren4zhen1, ta1 gong1zuo4 hen3 nu3li4",
      "translation_en": "My older brother's personality is very serious; he works very hard.",
      "translation_ko": "제 오빠의 성격은 매우 진지해서 일을 열심히 합니다."
    },
    {
      "text": "聽說那個新同學很害羞，不太說話。",
      "pinyin": "Tīngshuō nà ge xīn tóngxué hěn hàixiū, bù tài shuōhuà.",
      "pinyin_numeric": "ting1shuo1 na4 ge5 xin1 tong2xue2 hen3 hai4xiu1, bu4 tai4 shuo1hua4",
      "translation_en": "I heard that new classmate is very shy and doesn't talk much.",
      "translation_ko": "그 새 친구는 매우 수줍어해서 말을 많이 하지 않는다고 들었습니다."
    },
    {
      "text": "他長得不高，可是他的個性很大方。",
      "pinyin": "Tā zhǎng de bù gāo, kěshì tā de gèxìng hěn dàfāng.",
      "pinyin_numeric": "ta1 zhang3 de5 bu4 gao1, ke3shi4 ta1 de5 ge4xing4 hen3 da4fang1",
      "translation_en": "He is not tall, but his personality is very generous.",
      "translation_ko": "그는 키가 크지 않지만, 성격은 매우 대범합니다."
    },
    {
      "text": "我媽媽的眼睛很大，她看起來很溫柔。",
      "pinyin": "Wǒ māma de yǎnjīng hěn dà, tā kàn qǐlái hěn wēnróu.",
      "pinyin_numeric": "wo3 ma1ma5 de5 yan3jing1 hen3 da4, ta1 kan4 qi3lai2 hen3 wen1rou2",
      "translation_en": "My mother's eyes are very big; she looks very gentle.",
      "translation_ko": "제 어머니의 눈은 매우 커서 매우 온화해 보입니다."
    },
    {
      "text": "那個男生很帥，而且個性很有趣。",
      "pinyin": "Nà ge nánshēng hěn shuài, érqiě gèxìng hěn yǒuqù.",
      "pinyin_numeric": "na4 ge5 nan2sheng1 hen3 shuai4, er2qie3 ge4xing4 hen3 you3qu4",
      "translation_en": "That guy is very handsome, and his personality is very interesting.",
      "translation_ko": "그 남학생은 매우 잘생겼고, 성격도 매우 재미있습니다."
    }
  ]
}
